// Generates src/generated/spriteManifest.ts: the list of every sprite URL
// Run automatically before build/start (see package.json). Do not edit the output!
import { readdirSync, writeFileSync, mkdirSync } from 'node:fs';
import { join, relative, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const spritesDir = join(root, 'assets', 'sprites');
const outFile = join(root, 'src', 'generated', 'spriteManifest.ts');
const exts = new Set(['.png', '.webp', '.gif', '.jpg', '.jpeg']);

function walk(dir) {
	const out = [];
	for (const entry of readdirSync(dir, { withFileTypes: true })) {
		const full = join(dir, entry.name);
		if (entry.isDirectory()) out.push(...walk(full));
		else if (
			exts.has(entry.name.slice(entry.name.lastIndexOf('.')).toLowerCase())
		)
			out.push(relative(root, full).split('\\').join('/'));
	}
	return out;
}

const files = walk(spritesDir).sort();
const body = files.map(f => `\t'${f}',`).join('\n');
const contents = `// AUTO-GENERATED by scripts/generate-sprite-manifest.mjs - do not edit.\n// ${files.length} sprites.\nexport const SPRITE_MANIFEST: readonly string[] = [\n${body}\n];\n`;

mkdirSync(dirname(outFile), { recursive: true });
writeFileSync(outFile, contents);
console.log(
	`[sprite-manifest] wrote ${files.length} sprites -> ${relative(root, outFile)}`
);
